import React from "react";
import { useParams } from "react-router-dom";

const newsData = [
  {
    id: "1",
    title: "Leniency in Criminal Sentence for Justice Collaborators...",
    date: "06 February, 2025",
    image: "/images/news1.jpg",
    content: `
      <h2>I. INTRODUCTION</h2>
      <p>The key to a successful criminal law enforcement depends on...</p>
      <h2>II. DISCUSSION</h2>
      <p>Definition of Justice Collaborator and Conditions to Be Met...</p>
    `,
  },
  // Add more news items...
];

function NewsDetail() {
  const { id } = useParams();
  const newsItem = newsData.find((news) => news.id === id);

  if (!newsItem) {
    return <h2>News Not Found</h2>;
  }

  return (
    <div className="news-detail">
      <h1>{newsItem.title}</h1>
      <p>{newsItem.date}</p>
      <img src={newsItem.image} alt={newsItem.title} />
      <div dangerouslySetInnerHTML={{ __html: newsItem.content }} />
    </div>
  );
}

export default NewsDetail;
